        if words[1] == "an":
            if words[2] == "integer":
                if words[3] == "y":
                    # Generate the input for finding an integer y
                    input_str = "var int: y;\nconstraint y == 10;\nsolve satisfy;"
                    return input_str
                else:
                    # Handle invalid syntax
