class Model:
    def __init__(self):
        self.var_decls = []
        self.constraints = []
        self.solve = None
        self.output_opt = ""

def parse_user_intent(intent):
    # Split the intent into parts
    parts = intent.split('\n')

    # Parse each part to extract relevant information
    for part in parts:
        if part.strip() == "":
            continue

        if part.startswith('var'):
            self.parse_var_decls(part)
        elif part.startswith('constraint'):
            self.parse_constraint(part)
        elif part.startswith('solve'):
            self.parse_solve(part)
        elif part.startswith('output'):
            self.parse_output_opt(part)

def parse_var_decls(line):
    parts = line.split()
    if len(parts) != 4:
        raise ValueError("Invalid var_decl format")
    var_type = parts[1]
    var_name = parts[3]
    self.var_decls.append((var_type, var_name))

def parse_constraint(line):
    parts = line.split()
    if len(parts) != 3:
        raise ValueError("Invalid constraint format")
    operator = parts[1]
    right_hand_side = parts[2]
    self.constraints.append((operator, right_hand_side))

def parse_solve(line):
    parts = line.split()
    if len(parts) != 2:
        raise ValueError("Invalid solve format")
    if parts[0] == "satisfy":
        self.solve = "satisfy"
    else:
        self.solve = f"maximize {parts[1]}"
        self.solve += f" or minimize {parts[1]}"

def parse_output_opt(line):
    parts = line.split()
    if len(parts) != 2:
        raise ValueError("Invalid output_opt format")
    if parts[0] == "output":
        show_statement = parts[1].strip()[6:]
        self.output_opt = f"show({show_statement});"

# Example usage
intent = """
var int: y;
constraint y == 10;
solve satisfy;
output [show(y)];
"""
parse_user_intent(intent)
print(model)

