import re

class Model:
    def __init__(self):
        self.var_decls = []
        self.constraints = []
        self.solve = None
        self.output_opt = ""

    def parse(self, input_str):
        # Split the input string into lines
        lines = input_str.strip().split('\n')

        # Parse each line
        for line in lines:
            if line.startswith('var'):
                self.parse_var(line)
            elif line.startswith('constraint'):
                self.parse_constraint(line)
            elif line.startswith('solve'):
                self.parse_solve(line)
            elif line.startswith('output'):
                self.parse_output(line)

    def parse_var(self, line):
        match = re.match(r'var (\w+): (\w+) \((\d+)\);', line)
        if match:
            name, type, range_str = match.groups()
            min_val, max_val = map(int, range_str.split(".."))
            self.var_decls.append({'name': name, 'type': type, 'range': (min_val, max_val)})

    def parse_constraint(self, line):
        match = re.match(r'constraint (\w+) \((.*)\);', line)
        if match:
            name, condition = match.groups()
            self.constraints.append(name + ': ' + condition)

    def parse_solve(self, line):
        match = re.match(r'solve (.*)', line)
        if match:
            self.solve = match.group(1)

    def parse_output(self, line):
        if line.startswith('output'):
            match = re.match(r'output \[(show(\w+)?)\]\;', line)
            if match:
                self.output_opt = match.group(1) or ''

# Example usage
model = Model()
input_str = """
var int: y;
constraint y == 10;
solve satisfy;
"""
model.parse(input_str)
print(model.var_decls)
print(model.constraints)
print(model.solve)
print(model.output_opt)

