import re

class GrammarParser:
    def __init__(self):
        self.model = None
        self.var_decls = []
        self.constraints = []
        self.solve = None
        self.output_opt = ""

    def parse(self, input_string):
        self.model = self.parse_model(input_string)
        return self.model

    def parse_model(self, input_string):
        match = re.search(r'^(var\s+)?(constraints\s+)?(solve\s+)(satisfy|maximize\s+(\w+)|minimize\s+(\w+))(\s+output\s+\[(\w+)\]\s*);?\s*', input_string)
        if not match:
            raise ValueError("Invalid input string")

        var_decls = self.parse_var_decls(match.group(1))
        constraints = self.parse_constraints(match.group(2))
        solve = self.parse_solve(match.group(3), match.group(4))
        output_opt = match.group(6) or ""

        return {
            "var_decls": var_decls,
            "constraints": constraints,
            "solve": solve,
            "output_opt": output_opt
        }

    def parse_var_decls(self, input_string):
        var_decls_list = []
        while input_string:
            match = re.match(r'(var\s+(int|bool|int\.\.\.int|set\s+of\s+int\.\.\.int)\s+:\s+IDENT\s*;)', input_string)
            if not match:
                break

            var_name = match.group(3)
            var_type = match.group(2)
            var_decls_list.append((var_name, var_type))

            input_string = input_string[match.end():]

        return var_decls_list

    def parse_constraints(self, input_string):
        constraints_list = []
        while input_string:
            match = re.match(r'(constraint\s+expr\s*;)', input_string)
            if not match:
                break

            expr = self.parse_expr(match.group(1))
            constraints_list.append(expr)

            input_string = input_string[match.end():]

        return constraints_list

    def parse_solve(self, input_string, solve_type):
        if solve_type == "satisfy":
            return {
                "type": solve_type
            }
        elif solve_type in ["maximize", "minimize"]:
            var_name = re.search(r'maximize|minimize\s+(\w+)', input_string).group(1)
            return {
                "type": solve_type,
                "variable": var_name
            }
        else:
            raise ValueError("Invalid solve type")

    def parse_expr(self, input_string):
        match = re.match(r'(math_expr|comp_expr)', input_string)
        if match:
            return self.parse_math_expr(match.group(1))
        else:
            return self.parse_comp_expr(input_string)

    def parse_math_expr(self, input_string):
        match = re.match(r'(term|term\s+math_op\s+term)', input_string)
        if match:
            left_term = self.parse_term(match.group(1))
            right_term = self.parse_term(match.group(3))
            operator = match.group(2)
            return {
                "left": left_term,
                "operator": operator,
                "right": right_term
            }
        else:
            return self.parse_term(input_string)

    def parse_term(self, input_string):
        match = re.match(r'(IDENT|int)', input_string)
        if match:
            return {
                "value": match.group(1)
            }
        else:
            raise ValueError("Invalid term")

    def parse_comp_expr(self, input_string):
        match = re.match(r'(math_expr|math_expr\s+comp_op\s+math_expr)', input_string)
        if match:
            left_expr = self.parse_math_expr(match.group(1))
            right_expr = self.parse_math_expr(match.group(3))
            operator = match.group(2)
            return {
                "left": left_expr,
                "operator": operator,
                "right": right_expr
            }
        else:
            return self.parse_math_expr(input_string)

# Example usage
parser = GrammarParser()
input_string = """
var int: y;
constraint y == 10;
solve satisfy;
"""
result = parser.parse(input_string)
print(result)

