# Define the grammar rules using Python classes

class GrammarRule:
    def __init__(self, name, *args):
        self.name = name
        self.args = args

class VariableDeclaration(GrammarRule):
    def __init__(self, name, type, range=None):
        super().__init__("var_decl", name, type)
        self.range = range

class Type(GrammarRule):
    def __init__(self, name):
        super().__init__("type", name)

class Constraint(GrammarRule):
    def __init__(self, expression):
        super().__init__("constraint", expression)

class Expression(GrammarRule):
    def __init__(self, value):
        super().__init__("expr", value)

class LogicExpression(GrammarRule):
    def __init__(self, left, operator, right):
        super().__init__("logic_expr", left, operator, right)

class CompExpression(GrammarRule):
    def __init__(self, left, operator, right):
        super().__init__("comp_expr", left, operator, right)

class MathExpression(GrammarRule):
    def __init__(self, left, operator, right):
        super().__init__("math_expr", left, operator, right)

class Term(GrammarRule):
    def __init__(self, name):
        super().__init__("term", name)

class Range(GrammarRule):
    def __init__(self, start, end):
        super().__init__("range", start, end)

# Define the grammar rules
grammar_rules = {
    "start": GrammarRule("model"),
    "model": GrammarRule("var_decls", "constraints", "solve", "output_opt"),
    "var_decls": GrammarRule("var_decl", "var_decls"),
    "var_decl": GrammarRule("var", "type", ":", "IDENT", ";", "\n") | GrammarRule("array", "[", int_lit, "..", int_lit], "of", "var", "type", ":", "IDENT", ";", "\n"),
    "type": GrammarRule("int") | GrammarRule("bool") | GrammarRule(int_lit, "..", int_lit) | GrammarRule("set of", int_lit, "..", int_lit),
    "constraints": GrammarRule("constraint", "constraints"),
    "constraint": GrammarRule("constraint", "expr", ";", "\n"),
    "expr": GrammarRule("logic_expr"),
    "logic_expr": GrammarRule("comp_expr") | GrammarRule("comp_expr", " ", "logic_op", " ", "logic_expr"),
    "comp_expr": GrammarRule("math_expr") | GrammarRule("math_expr", " ", comp_op, " ", "math_expr") | GrammarRule("sum", "(", IDENT, ")") | GrammarRule("comp_op", "==", ">", "<", "!=", "<=", ">=", "in"),
    "math_expr": GrammarRule("term") | GrammarRule("term", " ", math_op, " ", "math_expr"),
    "term": GrammarRule("IDENT") | GrammarRule("int_lit"),
    "math_op": GrammarRule("+", "-", "*", "/", "mod"),
    "comp_op": GrammarRule("==", ">", "<", "!=", "<=", ">=", "in"),
    "logic_op": GrammarRule("\\/", "/\\", "->"),
    "solve": GrammarRule("solve", "satisfy", ";", "\n") | GrammarRule("solve", "maximize", "IDENT", ";", "\n") | GrammarRule("solve", "minimize", "IDENT", ";", "\n"),
    "output_opt": GrammarRule("output", "[", "show", "(", IDENT, ")"], ";", "\n") | GrammarRule("output_opt", ""),
    "IDENT": GrammarRule("[a-zA-Z_][a-zA-Z0-9_]*"),
    "int_lit": GrammarRule("-?[0-9]+")
}

# Function to parse user intent into the grammar rules
def parse_user_intent(intent):
    # Split the intent into words
    words = intent.split()

    # Initialize the current rule
    current_rule = grammar_rules["start"]

    # Process each word
    for word in words:
        if word in grammar_rules:
            current_rule = grammar_rules[word]
        else:
            raise ValueError(f"Unknown keyword: {word}")

    return current_rule

# Example usage
intent = "Find an integer y exactly equal to 10."
parsed_intent = parse_user_intent(intent)
